## Object Storage Bucket

```hcl
resource "oci_object_storage_bucket" "bucket" {
  compartment_id = var.compartment_id
  namespace      = var.namespace
  name          = "my-bucket"
  storage_tier  = "Standard"
  versioning    = "Enabled"
}
```

### Lifecycle Policy

```hcl
resource "oci_object_storage_bucket" "tiered" {
  compartment_id = var.compartment_id
  namespace      = var.namespace
  name          = "tiered-bucket"

  lifecycle_policy {
    items {
      target     = "ARCHIVE"
      days_after_modification_greater_than = 30
    }
  }
}
```

### Pre-Authenticated Request

```hcl
resource "oci_object_storage_preauthrequest" "par" {
  bucket    = oci_object_storage_bucket.bucket.name
  namespace = var.namespace
  name     = "my-par"
  object   = "data/file.csv"
  time_expires = "2025-12-31T00:00:00Z"
}
